const clipItems = $('When Executed by Another Workflow').all();

if (!clipItems.length) {
  throw new Error('Keine Hauptclips im Input vorhanden.');
}

const config = $('Intro/Outro').first().json;
const srtUrl = $('build srt file').first().json.srtUrl;

const INTRO_IMAGE_URL = config.intro_image_url ?? '';
const INTRO_AUDIO_URL = config.intro_audio_url ?? '';
const OUTRO_IMAGE_URL = config.outro_image_url ?? '';
const OUTRO_AUDIO_URL = config.outro_audio_url ?? '';

const INTRO_LENGTH = Number(config.intro_length ?? 2.2);
const OUTRO_LENGTH = Number(config.outro_length ?? 6.0);

const OUTPUT_WIDTH = Number(config.output_width ?? 1080);
const OUTPUT_HEIGHT = Number(config.output_height ?? 1920);
const OUTPUT_FORMAT = config.output_format ?? 'mp4';

const MAIN_CLIP_GAP = Number(config.main_clip_gap ?? 0);
const DURATION_BUFFER = Number(config.duration_buffer ?? 0.12);

const CAPTION_ENABLED =
  String(config.captions_enabled ?? config.caption_enabled ?? 'true').toLowerCase() === 'true';

// TikTok/Reels Style
const CAPTION_FONT_SIZE = Number(config.caption_font_size ?? 50);
const CAPTION_FONT_FAMILY = config.caption_font_family ?? 'Montserrat ExtraBold';
const CAPTION_TEXT_COLOR = config.caption_text_color ?? '#ffffff';
const CAPTION_LINE_HEIGHT = Number(config.caption_line_height ?? 0.9);
const CAPTION_STROKE_COLOR = config.caption_stroke_color ?? '#000000';
const CAPTION_STROKE_WIDTH = Number(config.caption_stroke_width ?? 2.9);
const CAPTION_OFFSET_Y = Number(config.caption_offset_y ?? 0.05);

function round2(n) { return Number(Number(n).toFixed(2)); }
function round3(n) { return Number(Number(n).toFixed(3)); }

function buildTextMetrics(text = '') {
  const t = String(text).trim();
  const words = t.split(/\s+/).filter(Boolean);
  const normalizedWords = words.map(w => w.replace(/[^\w-]/g, ''));
  const wordCount = words.length;
  const hasNumericContent = /[0-9$%€]/.test(t) || /\b(million|billion|trillion|thousand)\b/i.test(t) || /\b(19|20)\d{2}\b/.test(t);
  const acronymCount = words.filter(w => /\b[A-Z]{2,}\b/.test(w.replace(/[^\w]/g, ''))).length;
  const hyphenatedCount = words.filter(w => /-/.test(w)).length;
  const longWords = normalizedWords.filter(w => w.length >= 10).length;
  const veryLongWords = normalizedWords.filter(w => w.length >= 13).length;
  const punctuationCount = (t.match(/[,:;—-]/g) || []).length;
  const isComplexPhrase = hyphenatedCount >= 1 && acronymCount >= 1 && longWords >= 2;
  return { text: t, wordCount, hasNumericContent, acronymCount, hyphenatedCount, longWords, veryLongWords, punctuationCount, isComplexPhrase };
}

function calcDuration(text = '') {
  const metrics = buildTextMetrics(text);
  const base = metrics.wordCount / 2.35;
  let extra = 0.6;
  if (metrics.hasNumericContent) extra += 0.75;
  if (metrics.acronymCount >= 1) extra += 0.25;
  if (metrics.acronymCount >= 2) extra += 0.15;
  if (metrics.hyphenatedCount >= 1) extra += 0.2;
  if (metrics.hyphenatedCount >= 2) extra += 0.1;
  if (metrics.longWords >= 2) extra += 0.2;
  if (metrics.longWords >= 4) extra += 0.15;
  if (metrics.veryLongWords >= 1) extra += 0.15;
  if (metrics.veryLongWords >= 2) extra += 0.1;
  if (metrics.punctuationCount >= 2) extra += 0.2;
  if (metrics.punctuationCount >= 4) extra += 0.1;
  if (metrics.wordCount >= 14) extra += 0.2;
  if (metrics.wordCount >= 18) extra += 0.15;
  if (metrics.isComplexPhrase) extra += 0.3;
  return round3(Math.max(5.2, base + extra + 0.45));
}

const sorted = [...clipItems].sort((a, b) =>
  Number(a.json.clipIndex ?? 0) - Number(b.json.clipIndex ?? 0)
);

const imageClips = [];
const audioClips = [];
const debugClips = [];

let currentStart = 0;

// Intro
if (INTRO_IMAGE_URL && INTRO_AUDIO_URL) {
  imageClips.push({ start: round2(currentStart), length: round3(INTRO_LENGTH), asset: { type: 'image', src: INTRO_IMAGE_URL } });
  audioClips.push({ start: round2(currentStart), length: round3(INTRO_LENGTH), asset: { type: 'audio', src: INTRO_AUDIO_URL } });
  currentStart = round2(currentStart + INTRO_LENGTH);
}

// Hauptclips
for (const item of sorted) {
  const j = item.json;
  const clipIndex = Number(j.clipIndex ?? 0);
  const imageUrl = j.image_url;
  const audioUrl = j.audio_url;
  const voiceoverText = j.voiceover_text ?? '';

  if (!imageUrl) throw new Error(`image_url fehlt bei clipIndex ${clipIndex}`);
  if (!audioUrl) throw new Error(`audio_url fehlt bei clipIndex ${clipIndex}`);

  const metrics = buildTextMetrics(voiceoverText);
  const rawDuration = j.duration;
  const hasRealDuration = rawDuration != null && rawDuration !== '';
  const duration = hasRealDuration
    ? round3(Number(rawDuration) + DURATION_BUFFER)
    : calcDuration(voiceoverText);
  const start = round2(currentStart);
  const length = round3(duration);

  imageClips.push({ start, length, asset: { type: 'image', src: imageUrl } });
  audioClips.push({ start, length, asset: { type: 'audio', src: audioUrl } });

  debugClips.push({
    clipIndex,
    wordCount: metrics.wordCount,
    hasNumericContent: metrics.hasNumericContent,
    usedRealDuration: hasRealDuration,
    sourceDuration: hasRealDuration ? round3(Number(rawDuration)) : null,
    durationBuffer: hasRealDuration ? DURATION_BUFFER : null,
    start,
    length,
    voiceover_text: voiceoverText,
    audio_url: audioUrl,
  });

  currentStart = round2(currentStart + duration + MAIN_CLIP_GAP);
}

if (sorted.length > 0) {
  currentStart = round2(currentStart - MAIN_CLIP_GAP);
}

// Outro
if (OUTRO_IMAGE_URL && OUTRO_AUDIO_URL) {
  imageClips.push({ start: round2(currentStart), length: round3(OUTRO_LENGTH), asset: { type: 'image', src: OUTRO_IMAGE_URL } });
  audioClips.push({ start: round2(currentStart), length: round3(OUTRO_LENGTH), asset: { type: 'audio', src: OUTRO_AUDIO_URL } });
  currentStart = round2(currentStart + OUTRO_LENGTH);
}

const scriptId = sorted[0]?.json?.scriptId ?? null;

const tracks = [];

if (CAPTION_ENABLED && srtUrl) {
  tracks.push({
    clips: [{
      start: 0,
      length: 'end',
      position: 'bottom',
      offset: { x: 0, y: CAPTION_OFFSET_Y },
      asset: {
        type: 'caption',
        src: srtUrl,
        font: {
          family: CAPTION_FONT_FAMILY,
          size: CAPTION_FONT_SIZE,
          color: CAPTION_TEXT_COLOR,
          lineHeight: CAPTION_LINE_HEIGHT,
          stroke: CAPTION_STROKE_COLOR,
          strokeWidth: CAPTION_STROKE_WIDTH,
        },
      },
    }],
  });
}

tracks.push({ clips: imageClips });
tracks.push({ clips: audioClips });

const payload = {
  timeline: { tracks },
  output: {
    format: OUTPUT_FORMAT,
    size: { width: OUTPUT_WIDTH, height: OUTPUT_HEIGHT },
  },
};

return [{
  json: {
    scriptId,
    payload,
    debug: {
      captionEnabled: CAPTION_ENABLED,
      srtUrl: srtUrl ?? null,
      introIncluded: Boolean(INTRO_IMAGE_URL && INTRO_AUDIO_URL),
      outroIncluded: Boolean(OUTRO_IMAGE_URL && OUTRO_AUDIO_URL),
      introLength: INTRO_LENGTH,
      outroLength: OUTRO_LENGTH,
      totalDuration: round2(currentStart),
      clipCountMain: sorted.length,
      clipCountImages: imageClips.length,
      clipCountAudio: audioClips.length,
      clips: debugClips,
    },
  },
}];

const config = $input.first().json;
const clipItems = $('When Executed by Another Workflow').all();

const INTRO_IMAGE_URL = config.intro_image_url ?? '';
const INTRO_AUDIO_URL = config.intro_audio_url ?? '';
const INTRO_LENGTH = Number(config.intro_length ?? 2.2);
const INTRO_CAPTION = config.intro_caption ?? '';

const OUTRO_IMAGE_URL = config.outro_image_url ?? '';
const OUTRO_AUDIO_URL = config.outro_audio_url ?? '';
const OUTRO_LENGTH = Number(config.outro_length ?? 6.0);
const OUTRO_CAPTION = config.outro_caption ?? '';

const DURATION_BUFFER = Number(config.duration_buffer ?? 0.12);
const MAIN_CLIP_GAP = Number(config.main_clip_gap ?? 0.08);
const WORDS_PER_SEGMENT = 3;

function toSrtTime(seconds) {
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  const ms = Math.round((seconds % 1) * 1000);
  return `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')},${String(ms).padStart(3,'0')}`;
}

function addSegments(text, startTime, duration, wordsPerSegment, entryIndex, fullSrt) {
  const words = String(text).trim().split(/\s+/).filter(Boolean);
  if (!words.length) return { entryIndex, fullSrt };
  const segments = [];
  for (let i = 0; i < words.length; i += wordsPerSegment) {
    segments.push(words.slice(i, i + wordsPerSegment).join(' '));
  }
  const segDuration = duration / segments.length;
  segments.forEach((seg, idx) => {
    const start = startTime + idx * segDuration;
    const end = start + segDuration - 0.05;
    fullSrt += `${entryIndex}\n${toSrtTime(start)} --> ${toSrtTime(end)}\n${seg}\n\n`;
    entryIndex++;
  });
  return { entryIndex, fullSrt };
}

const sorted = [...clipItems].sort((a, b) =>
  Number(a.json.clipIndex ?? 0) - Number(b.json.clipIndex ?? 0)
);

const scriptId = sorted[0].json.scriptId;

let currentStart = 0;
let entryIndex = 1;
let fullSrt = '';

// Intro
const hasIntro = Boolean(INTRO_IMAGE_URL && INTRO_AUDIO_URL);
if (hasIntro && INTRO_CAPTION) {
  ({ entryIndex, fullSrt } = addSegments(INTRO_CAPTION, 0, INTRO_LENGTH, WORDS_PER_SEGMENT, entryIndex, fullSrt));
}
if (hasIntro) {
  currentStart = INTRO_LENGTH;
}

// Hauptclips
for (const item of sorted) {
  const j = item.json;
  const clipDuration = Number(j.duration) + DURATION_BUFFER;
  ({ entryIndex, fullSrt } = addSegments(j.voiceover_text, currentStart, clipDuration, WORDS_PER_SEGMENT, entryIndex, fullSrt));
  currentStart = currentStart + clipDuration + MAIN_CLIP_GAP;
}

if (sorted.length > 0) {
  currentStart = currentStart - MAIN_CLIP_GAP;
}

// Outro
const hasOutro = Boolean(OUTRO_IMAGE_URL && OUTRO_AUDIO_URL);
if (hasOutro && OUTRO_CAPTION) {
  ({ entryIndex, fullSrt } = addSegments(OUTRO_CAPTION, currentStart, OUTRO_LENGTH, WORDS_PER_SEGMENT, entryIndex, fullSrt));
}

const srtContent = fullSrt.trim();
const srtKey = `reels/${scriptId}/srt/full_transcript_${Date.now()}.srt`;
const srtUrl = `https://pub-b9cab7c4281d4ca4948989323fa68b5d.r2.dev/${srtKey}`;

const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(srtContent, 'utf-8'),
  'full_transcript.srt',
  'text/plain'
);

return [{
  json: {
    scriptId,
    srtKey,
    srtUrl,
    // Debug — zeigt ob Intro/Outro in SRT enthalten sind
    debug: {
      introCaptionFound: Boolean(INTRO_CAPTION),
      outroCaptionFound: Boolean(OUTRO_CAPTION),
      introCaptionValue: INTRO_CAPTION,
      outroCaptionValue: OUTRO_CAPTION,
      srtContent,
    }
  },
  binary: { data: binaryData },
}];
